#include <qpdf/Pl_RC4.hh>

#include <qpdf/QUtil.hh>
#include <qpdf/Util.hh>

using namespace qpdf;

Pl_RC4::Pl_RC4(char const* identifier, Pipeline* next, std::string key, size_t out_bufsize) :
    Pipeline(identifier, next),
    out_bufsize(out_bufsize),
    rc4(reinterpret_cast<unsigned char const*>(key.data()), static_cast<int>(key.size()))
{
    util::assertion(next, "Attempt to create Pl_RC4 with nullptr as next");
    this->outbuf = QUtil::make_shared_array<unsigned char>(out_bufsize);
}

void
Pl_RC4::write(unsigned char const* data, size_t len)
{
    util::assertion(outbuf.get(), "Pl_RC4: write() called after finish() called");

    size_t bytes_left = len;
    unsigned char const* p = data;

    while (bytes_left > 0) {
        size_t bytes = (bytes_left < this->out_bufsize ? bytes_left : out_bufsize);
        bytes_left -= bytes;
        rc4.process(p, bytes, outbuf.get());
        p += bytes;
        next()->write(outbuf.get(), bytes);
    }
}

void
Pl_RC4::finish()
{
    outbuf = nullptr;
    next()->finish();
}

#include <qpdf/QTC.hh>

#include <qpdf/QUtil.hh>
#include <cstdio>
#include <map>
#include <set>

static bool
tc_active(char const* const scope)
{
    std::string value;
    return (QUtil::get_env("TC_SCOPE", &value) && (value == scope));
}

void
QTC::TC_real(char const* const scope, char const* const ccase, int n)
{
    static std::map<std::string, bool> active;
    auto is_active = active.find(scope);
    if (is_active == active.end()) {
        active[scope] = tc_active(scope);
        is_active = active.find(scope);
    }

    if (!is_active->second) {
        return;
    }

    static std::set<std::pair<std::string, int>> cache;

    std::string filename;
#ifdef _WIN32
# define TC_ENV "TC_WIN_FILENAME"
#else
# define TC_ENV "TC_FILENAME"
#endif
    if (!QUtil::get_env(TC_ENV, &filename)) {
        return;
    }
#undef TC_ENV

    if (cache.contains(std::make_pair(ccase, n))) {
        return;
    }
    cache.insert(std::make_pair(ccase, n));

    FILE* tc = QUtil::safe_fopen(filename.c_str(), "ab");
    fprintf(tc, "%s %d\n", ccase, n);
    fclose(tc);
}

#include <qpdf/ResourceFinder.hh>

void
ResourceFinder::handleObject(QPDFObjectHandle obj, size_t offset, size_t)
{
    if (obj.isOperator() && !last_name.empty()) {
        static const std::map<std::string, std::string> op_to_rtype{
            {"CS", "/ColorSpace"},
            {"cs", "/ColorSpace"},
            {"gs", "/ExtGState"},
            {"Tf", "/Font"},
            {"SCN", "/Pattern"},
            {"scn", "/Pattern"},
            {"BDC", "/Properties"},
            {"DP", "/Properties"},
            {"sh", "/Shading"},
            {"Do", "/XObject"},
        };
        std::string op = obj.getOperatorValue();
        auto iter = op_to_rtype.find(op);
        if (iter == op_to_rtype.end()) {
            return;
        }
        names.insert(last_name);
        names_by_resource_type[iter->second][last_name].push_back(last_name_offset);
    } else if (obj.isName()) {
        last_name = obj.getName();
        last_name_offset = offset;
    }
}

